def cmd_status():
    with open('.minigit/index', 'r') as f:
        files = [l.strip() for l in f if l.strip()]
    print("Staged files:")
    if not files:
        print("(none)")
    else:
        for fn in files:
            print(fn)

def parse_commit(commit_hash):
    path = f'.minigit/commits/{commit_hash}'
    if not os.path.isfile(path):
        return None
    with open(path, 'r') as f:
        content = f.read()
    lines = content.splitlines()
    parent = ''
    timestamp = ''
    message = ''
    files = {}
    in_files = False
    for line in lines:
        if in_files:
            parts = line.split(' ', 1)
            if len(parts) == 2:
                files[parts[0]] = parts[1]
        elif line.startswith('parent: '):
            parent = line[8:]
        elif line.startswith('timestamp: '):
            timestamp = line[11:]
        elif line.startswith('message: '):
            message = line[9:]
        elif line == 'files:':
            in_files = True
    return {'parent': parent, 'timestamp': timestamp, 'message': message, 'files': files}

def cmd_diff(hash1, hash2):
    c1 = parse_commit(hash1)
    c2 = parse_commit(hash2)
    if c1 is None or c2 is None:
        print("Invalid commit")
        sys.exit(1)
    all_files = sorted(set(list(c1['files'].keys()) + list(c2['files'].keys())))
    for fn in all_files:
        if fn not in c1['files']:
            print(f"Added: {fn}")
        elif fn not in c2['files']:
            print(f"Removed: {fn}")
        elif c1['files'][fn] != c2['files'][fn]:
            print(f"Modified: {fn}")

def cmd_checkout(commit_hash):
    commit = parse_commit(commit_hash)
    if commit is None:
        print("Invalid commit")
        sys.exit(1)
    for fn, blob_hash in commit['files'].items():
        with open(f'.minigit/objects/{blob_hash}', 'rb') as f:
            data = f.read()
        with open(fn, 'wb') as f:
            f.write(data)
    with open('.minigit/HEAD', 'w') as f:
        f.write(commit_hash)
    with open('.minigit/index', 'w') as f:
        pass
    print(f"Checked out {commit_hash}")

def cmd_reset(commit_hash):
    if not os.path.isfile(f'.minigit/commits/{commit_hash}'):
        print("Invalid commit")
        sys.exit(1)
    with open('.minigit/HEAD', 'w') as f:
        f.write(commit_hash)
    with open('.minigit/index', 'w') as f:
        pass
    print(f"Reset to {commit_hash}")

def cmd_rm(filename):
    with open('.minigit/index', 'r') as f:
        lines = [l.strip() for l in f if l.strip()]
    if filename not in lines:
        print("File not in index")
        sys.exit(1)
    lines.remove(filename)
    with open('.minigit/index', 'w') as f:
        for line in lines:
            f.write(line + '\n')

def cmd_show(commit_hash):
    commit = parse_commit(commit_hash)
    if commit is None:
        print("Invalid commit")
        sys.exit(1)
    print(f"commit {commit_hash}")
    print(f"Date: {commit['timestamp']}")
    print(f"Message: {commit['message']}")
    print("Files:")
    for fn in sorted(commit['files'].keys()):
        print(f"  {fn} {commit['files'][fn]}")

